import React from "react";
import "./Dashboard.css";

export default function ProfileMenu() {
  return (
    <div className="dash-wrapper" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
      <div style={{ display: 'flex', gap: 32 }}>
        <a href="/dashboard" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Dashboard
        </a>
        <a href="/addnew" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Add New
        </a>
        <a href="#" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          History
        </a>
        <div style={{ position: 'relative', minWidth: 120 }}>
          <div
            tabIndex={0}
            style={{ minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}
            onFocus={e => e.currentTarget.parentNode.querySelector('.tools-menu').style.display = 'block'}
            onBlur={e => setTimeout(() => { if (e.currentTarget.parentNode.querySelector('.tools-menu')) e.currentTarget.parentNode.querySelector('.tools-menu').style.display = 'none'; }, 150)}
            onMouseEnter={e => e.currentTarget.parentNode.querySelector('.tools-menu').style.display = 'block'}
            onMouseLeave={e => e.currentTarget.parentNode.querySelector('.tools-menu').style.display = 'none'}
          >
            Tools
          </div>
          <div className="tools-menu" style={{ display: 'none', position: 'absolute', top: '100%', left: 0, minWidth: 180, background: '#fff', borderRadius: 10, boxShadow: '0 4px 16px rgba(0,0,0,0.12)', zIndex: 10, marginTop: 8 }}>
            <a href="#" style={{ display: 'block', padding: '12px 20px', color: '#0f9d58', textDecoration: 'none', fontWeight: 500, borderBottom: '1px solid #eaf8f0' }}>Monthly Graph</a>
            <a href="#" style={{ display: 'block', padding: '12px 20px', color: '#0f9d58', textDecoration: 'none', fontWeight: 500, borderBottom: '1px solid #eaf8f0' }}>Summary</a>
            <a href="#" style={{ display: 'block', padding: '12px 20px', color: '#0f9d58', textDecoration: 'none', fontWeight: 500, borderBottom: '1px solid #eaf8f0' }}>Upload Bills</a>
            <a href="#" style={{ display: 'block', padding: '12px 20px', color: '#0f9d58', textDecoration: 'none', fontWeight: 500 }}>Download Report</a>
          </div>
        </div>
      </div>
    </div>
  );
}
